import React, { Component } from 'react'
import parse from 'html-react-parser';

class ModelFillTheBlank extends Component {

    state = {
        id : this.props.db.id,
        description : this.props.db.description,
        wordOptionList : this.props.db.wordOptionList,
        sentenceList : this.props.db.sentenceList,
        sentenceAnswerList : this.props.db.sentenceAnswerList,
        wordAnswerList : this.props.db.wordAnswerList,
        isShowAnswer : false,
    }

    showAnswers = () => {
        this.setState({
          isShowAnswers : !this.state.isShowAnswers
        })
    }

    getInputs = () => {
        return document.getElementById(this.state.id).querySelectorAll("input")
    }

    checkAnswers = () => {
        this.getInputs().forEach((input, index) => {
            if(input.value === this.state.wordAnswerList[index]){
                input.style.border = "1px solid limegreen"
            } else{
                input.style.border = "1px solid orangered"
            }
        })
    }

    clearAnswers = () => {
        this.getInputs().forEach(input => {
            input.value = "";
            input.style.border = "none";
            input.style.borderBottom = "1px double";
        })
    }

    render() {
        return (
        <>    
        <h2>{this.state.description}</h2>
        <hr />    

        <div className="row mb-4">
            <div className="col-md-12">
                <ul>
                {
                    this.state.wordOptionList.map((word) => (
                        <li className="float-start me-5 mb-3">{word}</li>
                    ))
                }
                </ul>
            </div>
        </div>

        <div className="row">
            <div id={this.state.id} className="col-md-12 fill-the-blank">
                {this.state.sentenceList.map((sentence, index) => (
                    <p>
                        {/* <span>{index+1}. </span> */}
                        {parse(sentence)}
                    </p>
                ))}
            </div>
        </div>

        <div className="row mb-5">
            <div className="col-md-12">      
                <button onClick={this.checkAnswers} className="btn btn-primary float-end ms-3">Check</button>
                <button onClick={this.showAnswers} className="btn btn-primary float-end ms-3">
                    {
                    this.state.isShowAnswers ? "Hide Answers" : "Show Answers"
                    }
                </button>       
                <button onClick={this.clearAnswers} className="btn btn-primary float-end ms-3">Clear</button>                   
            </div>
        </div>

        {
        this.state.isShowAnswers
            ? <div className="row mb-5"> 
                <h2 className="mt-5">Answers</h2>
                <hr />
                {this.state.sentenceAnswerList.map((sentenceAnswer, index) => (
                    <p>
                        {/* <span>{index+1}. </span> */}
                        {parse(sentenceAnswer)}
                    </p>
                ))}
              </div>
            : null
        }
        </>
        )
    }
}

export default ModelFillTheBlank;