import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import DrinkContext from '../../contexts/DrinkContext';

class LearnDrinks extends Component {

  static contextType = DrinkContext;

  state = {
      drinks : this.context,
  }

    render() {
        return (
            <ModelLearnWords db={this.state.drinks} isThereArticolo={true} category="New Drink" />
        )
    }
}

export default LearnDrinks;