import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import HouseholdItemContext from '../../contexts/HouseholdItemContext';

class LearnHouseholdItems extends Component {

  static contextType = HouseholdItemContext;

  state = {
      householdItems : this.context,
  }

    render() {
        return (
            <ModelLearnWords db={this.state.householdItems} isThereArticolo={true} category="New Household Item" />
        )
    }
}

export default LearnHouseholdItems;