import React, { Component } from 'react'
import TrueOrFalseExercisesContext from '../../contexts/TrueOrFalseExercisesContext';
import ModelTrueOrFalse from '../models/ModelTrueOrFalse'

class TrueOrFalseExercises extends Component {

    static contextType = TrueOrFalseExercisesContext;

    state = {
        trueOrFalseExercises : this.context,
    }

    render() {
        return (
            <div className="container">
                <div className="row mt-5 mb-5">

                    <div className="col-md-9 mb-5">

                        <div className="tab-content">

                            {/* mi-presento-1 */}
                            <div className="tab-pane fade show active" id="mi-presento-1">
                                <ModelTrueOrFalse db={this.state.trueOrFalseExercises.miPresento1} />
                            </div>

                            {/* mi-presento-2 */}
                            <div className="tab-pane fade" id="mi-presento-2">
                                <ModelTrueOrFalse db={this.state.trueOrFalseExercises.miPresento2} />
                            </div>

                            {/* mi-presento-3 */}
                            <div className="tab-pane fade" id="mi-presento-3">
                                <ModelTrueOrFalse db={this.state.trueOrFalseExercises.miPresento3} />
                            </div>

                            {/* mi-presento-4 */}
                            <div className="tab-pane fade" id="mi-presento-4">
                                <ModelTrueOrFalse db={this.state.trueOrFalseExercises.miPresento4} />
                            </div>

                            {/* mi-presento-5 */}
                            <div className="tab-pane fade" id="mi-presento-5">
                                <ModelTrueOrFalse db={this.state.trueOrFalseExercises.miPresento5} />
                            </div>

                            {/* la-giornata-di-margherita */}
                            <div className="tab-pane fade" id="la-giornata-di-margherita">
                                <ModelTrueOrFalse db={this.state.trueOrFalseExercises.laGiornataDiMargherita} />
                            </div>
                        </div>   

                    </div>

                    <div className="col-md-3">

                        <div className="list-group" id="list-tab">

                            <h2>CATEGORIES</h2>
                            <hr />
                            {/* mi-presento-1 */}
                            <a className="list-group-item list-group-item-action active" data-mdb-toggle="list" href="#mi-presento-1">{this.state.trueOrFalseExercises.miPresento1.title}</a>

                            {/* mi-presento-2 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#mi-presento-2">{this.state.trueOrFalseExercises.miPresento2.title}</a>

                            {/* mi-presento-3 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#mi-presento-3">{this.state.trueOrFalseExercises.miPresento3.title}</a>

                            {/* mi-presento-4 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#mi-presento-4">{this.state.trueOrFalseExercises.miPresento4.title}</a>

                            {/* mi-presento-5 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#mi-presento-5">{this.state.trueOrFalseExercises.miPresento5.title}</a>                                                        

                            {/* la-giornata-di-margherita */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#la-giornata-di-margherita">{this.state.trueOrFalseExercises.laGiornataDiMargherita.title}</a>

                        </div>

                    </div>

                </div>
            </div>
        )
    }
}

export default TrueOrFalseExercises;