import React, { Component } from 'react'

class ModelMatching extends Component {

    state = {
        id : this.props.db.id,
        description : this.props.db.description,
        firstWordList : this.props.db.firstWordList,
        secondWordList : this.props.db.secondWordList,
        answerList : this.props.db.answerList,
        isShowAnswer : false
    }

    showAnswers = () => {
        this.setState({
          isShowAnswers : !this.state.isShowAnswers
        })
    }

    checkAnswers = () => {
        const inputContainer = document.getElementById(this.state.id)
        const inputList = inputContainer.querySelectorAll("input")

        inputList.forEach((input, index) => {
            if(input.value === this.state.answerList[index]){
                input.style.border = "1px solid limegreen"
            } else{
                input.style.border = "1px solid orangered"
            }
        })
    }

    clearAnswers = () => {
        const inputContainer = document.getElementById(this.state.id)
        const inputList = inputContainer.querySelectorAll("input")

        inputList.forEach(input => {
            input.value = "";
            input.style.border = "none";
            input.style.borderBottom = "1px double";
        })
    }

    render() {
        return (
            <>
            <h2>{this.state.description}</h2>
            <hr />
            <div className="row">

                <div className="col-md-4">
                    <ol>
                        {this.state.firstWordList.map((word, index) => (
                            <li className="mb-3 mt-3">{word}</li>
                        ))}
                    </ol>
                </div>

                <div className="col-md-4">
                    <ol type="a">
                        {this.state.secondWordList.map((word, index) => (
                            <li className="mb-3 mt-3">{word}</li>
                        ))}
                    </ol>
                </div>

                <div id={this.state.id} className="col-md-4">
                    <ol className="fill-the-blank">
                        {this.state.answerList.map((answer, index) => (
                            <li>
                                <input type="text" />
                            </li>
                        ))}
                    </ol>
                </div>

            </div>

            <hr />

            <div className="row mb-5">
                <div className="col-md-12">      
                    <button onClick={this.checkAnswers} className="btn btn-primary float-end ms-3">Check</button>
                    <button onClick={this.showAnswers} className="btn btn-primary float-end ms-3">
                        {
                        this.state.isShowAnswers ? "Hide Answers" : "Show Answers"
                        }
                    </button>       
                    <button onClick={this.clearAnswers} className="btn btn-primary float-end ms-3">Clear</button>                   
                </div>
            </div>

            {
            this.state.isShowAnswers
                ? <div className="row mb-5"> 
                    <h2 className="mt-5">Answers</h2>
                    <hr />
                    {this.state.answerList.map((answer, index) => (
                        <p><span>{index+1}. </span>{answer}</p>
                    ))}
                </div>
                : null
            }
            </>
        )
    }
}

export default ModelMatching;