import React, { Component } from 'react'
import ModelFillTheBlankWithVerbConjugations from "../../components/models/ModelFillTheBlankWithVerbConjugations";
import IndicativoPresenteContext from '../../contexts/IndicativoPresenteContext';

class IndicativoPresente extends Component {

    static contextType = IndicativoPresenteContext;

    state = {
        indicativoPresenteExercises : this.context,
    }

    render() {
        return (
        <>
        <h2>Verbi Regolari (-ARE, -ERE, -IRE)</h2>
        <hr />
        <table className="table table-bordered table-hover table-striped text-center">
            <thead>
                <tr>
                    <th className="h5 text-danger">#</th>
                    <th className="h5 text-danger">-ARE</th>
                    <th className="h5 text-danger">-ERE</th>
                    <th className="h5 text-danger">–IRE (come «partire»)</th>
                    <th className="h5 text-danger">–IRE (come «finire»)</th>
                </tr>
            </thead>
            <tbody>
                <tr>
                    <td className="h5">Io</td>
                    <td>-o</td>
                    <td>-o</td>
                    <td>-o</td>
                    <td>-isco</td>
                </tr>
                <tr>
                    <td className="h5">Tu</td>
                    <td>-i</td>
                    <td>-i</td>
                    <td>-i</td>
                    <td>-isci</td>
                </tr>
                <tr>
                    <td className="h5">Lui/Lei</td>
                    <td>-a</td>
                    <td>-e</td>
                    <td>-e</td>
                    <td>-isce</td>
                </tr>
                <tr>
                    <td className="h5">Noi</td>
                    <td>-iamo</td>
                    <td>-iamo</td>
                    <td>-iamo</td>
                    <td>-iamo</td>
                </tr>
                <tr>
                    <td className="h5">Voi</td>
                    <td>-ate</td>
                    <td>-ete</td>
                    <td>-ite</td>
                    <td>-ite</td>
                </tr>
                <tr>
                    <td className="h5">Loro</td>
                    <td>-ano</td>
                    <td>-ono</td>
                    <td>-ono</td>
                    <td>-iscono</td>
                </tr>
            </tbody>
        </table>

        <hr className="mt-5 mb-5" />

        <table className="table table-bordered table-hover table-striped text-center">
            <thead>
                <tr>
                    <th className="h5 text-danger">Parlare</th>
                    <th className="h5 text-danger">Scrivere</th>
                    <th className="h5 text-danger">Dormire</th>
                    <th className="h5 text-danger">Capire</th>
                </tr>
            </thead>
            <tbody>
                <tr>
                    <td>Io parlo</td>
                    <td>Io scrivo</td>
                    <td>Io dormo</td>
                    <td>Io capisco</td>
                </tr>
                <tr>
                    <td>Tu parli</td>
                    <td>Tu scrivi</td>
                    <td>Tu dormi</td>
                    <td>Tu capisci</td>
                </tr>
                <tr>
                    <td>Lui/Lei parla</td>
                    <td>Lui/Lei scrive</td>
                    <td>Lui/Lei dorme</td>
                    <td>Lui/Lei capisce</td>
                </tr>
                <tr>
                    <td>Noi parliamo</td>
                    <td>Noi scriviamo</td>
                    <td>Noi dormiamo</td>
                    <td>Noi capiamo</td>
                </tr>
                <tr>
                    <td>Voi parlate</td>
                    <td>Voi scrivete</td>
                    <td>Voi dormite</td>
                    <td>Voi capite</td>
                </tr>
                <tr>
                    <td>Loro parlano</td>
                    <td>Loro scrivono</td>
                    <td>Loro dormono</td>
                    <td>Loro capiscono</td>
                </tr>
            </tbody>
        </table>


        <h2 className="mt-5">Verbi Irregolari</h2>
        <hr />
        <table className="table table-bordered table-hover table-striped text-center">
            <thead>
                <tr>
                    <th className="h5 text-danger">Essere</th>
                    <th className="h5 text-danger">Avere</th>
                    <th className="h5 text-danger">Andare</th>
                    <th className="h5 text-danger">Fare</th>
                    <th className="h5 text-danger">Venire</th>
                </tr>
            </thead>
            <tbody>
                <tr>
                    <td>Io sono</td>
                    <td>Io ho</td>
                    <td>Io vado</td>
                    <td>Io faccio</td>
                    <td>Io vengo</td>
                </tr>
                <tr>
                    <td>Tu sei</td>
                    <td>Tu hai</td>
                    <td>Tu vai</td>
                    <td>Tu fai</td>
                    <td>Tu vieni</td>
                </tr>
                <tr>
                    <td>Lui/Lei è</td>
                    <td>Lui/Lei ha</td>
                    <td>Lui/Lei va</td>
                    <td>Lui/Lei fa</td>
                    <td>Lui/Lei viene</td>
                </tr>
                <tr>
                    <td>Noi siamo</td>
                    <td>Noi abbiamo</td>
                    <td>Noi andiamo</td>
                    <td>Noi facciamo</td>
                    <td>Noi veniamo</td>
                </tr>
                <tr>
                    <td>Voi siete</td>
                    <td>Voi avete</td>
                    <td>Voi andate</td>
                    <td>Voi fate</td>
                    <td>Voi venite</td>
                </tr>
                <tr>
                    <td>Loro sono</td>
                    <td>Loro hanno</td>
                    <td>Loro vanno</td>
                    <td>Loro fanno</td>
                    <td>Loro vengono</td>
                </tr>
            </tbody>
        </table>
        
        <h2 className="mt-5">Exercises</h2>
        <hr />
        
        <p><strong>A. Completare con la forma del presente indicativo.</strong></p>
        <ModelFillTheBlankWithVerbConjugations db={this.state.indicativoPresenteExercises[0]} />

        <hr />

        <p><strong>B. Completare con la forma del presente indicativo.</strong></p>
        <ModelFillTheBlankWithVerbConjugations db={this.state.indicativoPresenteExercises[1]} />
        </>
        )
    }
}

export default IndicativoPresente;