import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import CountriesContext from '../../contexts/CountriesContext';

class LearnCountries extends Component {

  static contextType = CountriesContext;

  state = {
      countries : this.context,
  }

    render() {
        return (
            <ModelLearnWords db={this.state.countries} isThereArticolo={true} category="New Country" />
        )
    }
}

export default LearnCountries;