import React, { Component } from 'react'
import {
    Link
  } from "react-router-dom";

class Navbar extends Component {
    render() {
        return (
            <nav className="navbar navbar-expand-lg navbar-light bg-info text-white">
                <div className="container">
                    <button className="navbar-toggler" type="button" data-mdb-toggle="collapse" data-mdb-target="#navbarNav"
                        aria-controls="navbarNav" aria-expanded="false" aria-label="Toggle navigation">
                        <i className="fas fa-bars"></i>
                    </button>
                    <div className="collapse navbar-collapse" id="navbarNav">
                        <ul className="navbar-nav">
                            <li className="nav-item active">
                                <Link className="nav-link" to="/">Home</Link>
                            </li>                    
                            <li className="nav-item">
                                <Link className="nav-link" to="/italian-grammar">Grammar</Link>
                            </li>
                            <li className="nav-item">
                                <Link className="nav-link" to="/italian-reading">Reading</Link>
                            </li>
                            <li className="nav-item">
                                <Link className="nav-link" to="/italian-verb-conjugations">Verb Conjugations</Link>
                            </li>
                            <li className="nav-item">
                                <Link className="nav-link" to="/italian-learn-words">Learn Words</Link>
                            </li>
                            <li className="nav-item dropdown">
                                <a className="nav-link dropdown-toggle" href="#" id="navbarDropdown" role="button" data-mdb-toggle="dropdown" aria-expanded="false" >
                                    Exercises
                                </a>
                                <ul className="dropdown-menu" aria-labelledby="navbarDropdown">
                                    <li><Link className="dropdown-item" to="/italian-exercises-true-or-false">True or False</Link></li>
                                    <li><Link className="dropdown-item" to="/italian-exercises-matching">Matching</Link></li>
                                    <li><Link className="dropdown-item" to="/italian-exercises-matching-with-image">Matching with image</Link></li>
                                    <li><Link className="dropdown-item" to="/italian-exercises-fill-the-blank">Fill the blank</Link></li>
                                </ul>
                            </li>
                            
                        </ul>
                    </div>
                </div>
            </nav>
        )
    }
}

export default Navbar;