import React, { Component } from 'react'
import FillTheBlankContext from '../../contexts/FillTheBlankContext';
import ModelFillTheBlank from '../models/ModelFillTheBlank'

class FillTheBlankExercises extends Component {

    static contextType = FillTheBlankContext;

    state = {
        fillTheBlankExercises : this.context,
    }

    render() {
        return (
            <div className="container">
                <div className="row mt-5 mb-5">

                    <div className="col-md-9">

                        <div className="tab-content">

                            {/* incontri-matteo-e-abdul */}
                            <div className="tab-pane fade show active" id="incontri-matteo-e-abdul">
                                <ModelFillTheBlank db={this.state.fillTheBlankExercises.incontriMatteoEAbdul} />
                            </div>

                            {/* cosa-fa-il-muratore */}
                            <div className="tab-pane fade" id="cosa-fa-il-muratore">
                                <ModelFillTheBlank db={this.state.fillTheBlankExercises.cosaFaIlMuratore} />
                            </div>

                        </div>   

                    </div>

                    <div className="col-md-3">

                        <div className="list-group" id="list-tab">

                            <h2>CATEGORIES</h2>
                            <hr />

                            {/* incontri-matteo-e-abdul */}
                            <a className="list-group-item list-group-item-action active" data-mdb-toggle="list" href="#incontri-matteo-e-abdul">{this.state.fillTheBlankExercises.incontriMatteoEAbdul.title}</a>

                            {/* cosa-fa-il-muratore */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#cosa-fa-il-muratore">{this.state.fillTheBlankExercises.cosaFaIlMuratore.title}</a>
                        </div>

                    </div>

                </div>
            </div>
        )
    }
}

export default FillTheBlankExercises;